import{_ as a,o as e,c as i,a5 as s}from"./chunks/framework.D9Kapg2s.js";const g=JSON.parse('{"title":"流水线与原理","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/pipeline.md","filePath":"zh/guide/pipeline.md"}'),d={name:"zh/guide/pipeline.md"};function r(l,t,n,o,h,c){return e(),i("div",null,[...t[0]||(t[0]=[s(`<h1 id="流水线与原理" tabindex="-1">流水线与原理 <a class="header-anchor" href="#流水线与原理" aria-label="Permalink to &quot;流水线与原理&quot;">​</a></h1><p>本页说明翻译 <strong>如何执行</strong>：多轮计划、内容保护、响应修复、批量与重试、质量裁决等。偏「为什么 / 内部怎么走」。</p><div class="tip custom-block"><p class="custom-block-title">查字段与界面步骤</p><ul><li>界面怎么配：<a href="/zh/guide/translation-config.html">翻译配置 · 使用</a></li><li>字段与默认值：<a href="/zh/guide/translation-config-reference.html">翻译配置 · 参考</a></li><li>CLI 配置文件：<a href="/zh/guide/configuration.html">配置文件与环境变量</a></li></ul></div><h2 id="作业如何跑起来" tabindex="-1">作业如何跑起来 <a class="header-anchor" href="#作业如何跑起来" aria-label="Permalink to &quot;作业如何跑起来&quot;">​</a></h2><p>创建翻译作业时，系统会 <strong>固化</strong> 当前执行计划快照，后台 Worker 按资源依次处理。</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Start([创建作业]) --&gt; Res[每个资源]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Res --&gt; Next{下一轮次}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Next --&gt;|extract| Ex[抽术语 → 写术语表]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Next --&gt;|translate| Tr[翻译段落]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Next --&gt;|adjudicate| Ad[复核质检问题]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Next --&gt;|完成| Done([结束])</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Ex --&gt; Next</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Tr --&gt; Next</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Ad --&gt; Next</span></span></code></pre></div><p><strong>翻译轮次内部（简要）：</strong></p><ol><li>内容保护（占位符替换）</li><li>组装上下文 → 调用 AI</li><li>还原占位符 / 后处理 / 可选 Ruby 还原</li><li>规则质检写回段落</li></ol><p>可选：执行配置中的 <strong>内联术语自举</strong> 会在翻译响应中一并抽术语。</p><p>推荐轮次顺序：<code>extract</code>（可选）→ <code>translate</code>（可多轮）→ <code>adjudicate</code>（可选）。</p><hr><h2 id="多轮翻译-级联回退" tabindex="-1">多轮翻译：级联回退 <a class="header-anchor" href="#多轮翻译-级联回退" aria-label="Permalink to &quot;多轮翻译：级联回退&quot;">​</a></h2><p>多个 <strong><code>translate</code> 轮次</strong> 不是「润色流水线」，而是 <strong>失败回退</strong>：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Round 1：尝试全部待译段落</span></span>
<span class="line"><span>  ├─ 成功 → 写入，该段结束</span></span>
<span class="line"><span>  └─ 失败 → 交给 Round 2</span></span>
<span class="line"><span>Round 2：只处理 Round 1 失败的段落</span></span>
<span class="line"><span>  └─ …</span></span></code></pre></div><p><strong>典型用途：</strong> 主模型失败换备用模型；第二轮更小批次 / 更低并发提高成功率。</p><p>提取轮次在翻译前写术语；裁决轮次在规则质检之后做降噪。配置入口见 <a href="/zh/guide/translation-config.html#执行计划">翻译配置 · 使用 · 执行计划</a>。</p><hr><h2 id="批量与并发" tabindex="-1">批量与并发 <a class="header-anchor" href="#批量与并发" aria-label="Permalink to &quot;批量与并发&quot;">​</a></h2><p>每轮按 <code>batch_size</code>（段落数）与/或 <code>max_words_per_batch</code>（字词数）组批，Worker 池并发请求。</p><ul><li>CJK 常按字符计词；非 CJK 常按空白分词</li><li>批次会带上上下文窗口，保证连贯</li><li><strong>失败降级</strong>：整批失败时按 <code>fallback_shrink</code> 缩小批次（默认约一半）再试，最小可到 1 段</li><li>仍失败的段落可进入下一翻译轮次</li></ul><p>字段表见 <a href="/zh/guide/translation-config-reference.html#translate">翻译配置 · 参考 · translate</a>。</p><hr><h2 id="内容保护" tabindex="-1">内容保护 <a class="header-anchor" href="#内容保护" aria-label="Permalink to &quot;内容保护&quot;">​</a></h2><p>翻译前将代码、链接、占位符、HTML 标签等换成 <code>__LF_000001__</code> 形式（固定宽度编号），译后还原。</p><ul><li>默认规则：<code>code</code> / <code>link</code> / <code>placeholder</code> / <code>xml</code></li><li>相邻占位符可能合并，减少对模型的干扰</li><li>模型应 <strong>原样保留</strong> 占位符字符串</li></ul><p>规则列表见 <a href="/zh/guide/translation-config-reference.html#内容保护-protect">翻译配置 · 参考 · protect</a>。</p><hr><h2 id="上下文窗口" tabindex="-1">上下文窗口 <a class="header-anchor" href="#上下文窗口" aria-label="Permalink to &quot;上下文窗口&quot;">​</a></h2><p>为当前段附带前后各 N 段作 <strong>只读参考</strong>（不译）。</p><ul><li>优先用保护前的原文，便于模型阅读</li><li><code>max_chars</code> &gt; 0 时在句末附近截断</li><li>跳过空段、纯占位符、装饰分隔线</li></ul><p>参数见 <a href="/zh/guide/translation-config-reference.html#上下文-context">翻译配置 · 参考 · context</a>。</p><hr><h2 id="响应修复" tabindex="-1">响应修复 <a class="header-anchor" href="#响应修复" aria-label="Permalink to &quot;响应修复&quot;">​</a></h2><p>模型输出不总是合法 JSON。修复链大致包括：</p><table tabindex="0"><thead><tr><th>级别</th><th>内容</th></tr></thead><tbody><tr><td>结构</td><td>BOM/控制字符、括号、尾逗号等</td></tr><tr><td>别名</td><td><code>translation</code> / <code>result</code> 等映射到 <code>translations</code></td></tr><tr><td>部分结果</td><td>部分段缺失时只重试缺失段（受阈值控制）</td></tr><tr><td>占位符</td><td>大小写/下划线变体归一</td></tr><tr><td>提示升级</td><td>附加反例 reminder 再请求一次</td></tr></tbody></table><p>纯文本模式下还有去围栏、解析 <code>[glossary]</code> / <code>[ruby]</code> 等逻辑。开关见 <a href="/zh/guide/translation-config-reference.html#响应修复-repair">翻译配置 · 参考 · repair</a>。</p><hr><h2 id="术语提取-bootstrap" tabindex="-1">术语提取（Bootstrap） <a class="header-anchor" href="#术语提取-bootstrap" aria-label="Permalink to &quot;术语提取（Bootstrap）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>机制</th></tr></thead><tbody><tr><td><strong>独立提取</strong>（计划 <code>extract</code> 或 pre）</td><td>译前单独调用，写术语表，后续翻译轮次共享</td></tr><tr><td><strong>内联</strong>（执行配置 bootstrap）</td><td>翻译响应中顺带返回术语，省一次调用</td></tr></tbody></table><p>内联冲突策略：</p><table tabindex="0"><thead><tr><th>策略</th><th>行为</th></tr></thead><tbody><tr><td><code>rewrite-local</code>（默认）</td><td>冲突时以术语表权威译法改写本批译文</td></tr><tr><td><code>off</code></td><td>先到先得，文档内可能不一致</td></tr></tbody></table><p>产品操作见 <a href="/zh/guide/glossary.html">术语表管理</a>；字段见 <a href="/zh/guide/translation-config-reference.html#术语自举-bootstrap">翻译配置 · 参考</a>。</p><hr><h2 id="规则质检与-ai-质量裁决" tabindex="-1">规则质检与 AI 质量裁决 <a class="header-anchor" href="#规则质检与-ai-质量裁决" aria-label="Permalink to &quot;规则质检与 AI 质量裁决&quot;">​</a></h2><h3 id="规则质检" tabindex="-1">规则质检 <a class="header-anchor" href="#规则质检" aria-label="Permalink to &quot;规则质检&quot;">​</a></h3><p>翻译后自动标问题，例如：</p><table tabindex="0"><thead><tr><th>code</th><th>含义</th><th>可否 AI 裁决</th></tr></thead><tbody><tr><td><code>length_ratio</code></td><td>过短/过长</td><td>✅ 软规则</td></tr><tr><td><code>duplicate</code></td><td>相邻译文重复</td><td>❌ 硬规则</td></tr><tr><td><code>untranslated</code></td><td>译文=原文</td><td>❌ 硬规则</td></tr><tr><td><code>source_residual</code></td><td>译文夹源语脚本</td><td>✅ 软规则</td></tr></tbody></table><p>源语残留按 Unicode 脚本与语言对分档（独立脚本偏严；共汉字语言对有不同策略）。源语言为 <code>auto</code> 时残留检测不生效。</p><p>审校筛选见 <a href="/zh/guide/review.html#质量检测">翻译审校</a>。</p><h3 id="质量裁决-adjudicate" tabindex="-1">质量裁决（<code>adjudicate</code>） <a class="header-anchor" href="#质量裁决-adjudicate" aria-label="Permalink to &quot;质量裁决（\`adjudicate\`）&quot;">​</a></h3><p>对软规则问题逐条问 AI：<code>real</code> 保留 / <code>false_positive</code> 剔除。</p><ol><li>只处理已译/已改且带可裁决 code 的段落</li><li>分批调用 <strong>内置</strong> 裁决提示词</li><li>解析失败时 <strong>保留原问题</strong>，不清空</li></ol><p><strong>建议：</strong> 放在翻译轮次之后；专有名词多的文档优先开 <code>source_residual</code>。配置见 <a href="/zh/guide/translation-config.html#进阶组合">翻译配置 · 使用</a>。</p><hr><h2 id="ruby-注音" tabindex="-1">Ruby 注音 <a class="header-anchor" href="#ruby-注音" aria-label="Permalink to &quot;Ruby 注音&quot;">​</a></h2><p>含 <code>&lt;ruby&gt;</code> 的 HTML：</p><ol><li><strong>译前</strong> 抽出注音，正文只留 base</li><li><strong>译后</strong> 按类型过滤，把标签插回译文</li><li>本地对齐失败时，可用计划级 <strong>Ruby 重试</strong> 再调一次 LLM</li></ol><p>类型：<code>phonetic</code> / <code>semantic</code> / <code>creative</code>。字段见 <a href="/zh/guide/translation-config-reference.html#ruby-ruby">翻译配置 · 参考 · ruby</a>。</p><hr><h2 id="速率限制与重试" tabindex="-1">速率限制与重试 <a class="header-anchor" href="#速率限制与重试" aria-label="Permalink to &quot;速率限制与重试&quot;">​</a></h2><h3 id="限速" tabindex="-1">限速 <a class="header-anchor" href="#限速" aria-label="Permalink to &quot;限速&quot;">​</a></h3><p>后端 <code>rate_limit_per_minute</code>：令牌桶，超限等待而非丢弃。<code>0</code> 表示不限。</p><h3 id="错误策略-摘要" tabindex="-1">错误策略（摘要） <a class="header-anchor" href="#错误策略-摘要" aria-label="Permalink to &quot;错误策略（摘要）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>场景</th><th>行为</th></tr></thead><tbody><tr><td>429 / 503</td><td>退避后重试；尊重 <code>Retry-After</code>，常有最小等待</td></tr><tr><td>网络/超时</td><td>缩小批次再试</td></tr><tr><td>解析失败</td><td>先提示升级修复，再缩小批次</td></tr><tr><td>401 / 403</td><td>不重试，留给后续轮次</td></tr><tr><td>部分段缺失</td><td>同轮再组批一次</td></tr></tbody></table><p>重试参数：<code>max_attempts</code> / <code>backoff_ms</code> / <code>jitter</code>（指数退避 + 抖动）。见 <a href="/zh/guide/translation-config-reference.html#重试-retry">翻译配置 · 参考 · 重试</a>。</p><hr><h2 id="插件-规划中" tabindex="-1">插件（规划中） <a class="header-anchor" href="#插件-规划中" aria-label="Permalink to &quot;插件（规划中）&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">尚未实现</p><p>计划通过 Lua 脚本挂 <code>before_translate</code> / <code>after_translate</code> 等钩子。当前仅有接口与配置占位，请勿依赖。</p></div><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">plugins</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  scripts</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: []</span></span></code></pre></div><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/zh/guide/translation-config.html">翻译配置 · 使用</a> · <a href="/zh/guide/translation-config-reference.html">翻译配置 · 参考</a></li><li><a href="/zh/guide/review.html">翻译审校</a> · <a href="/zh/guide/glossary.html">术语表管理</a></li><li><a href="/zh/guide/faq.html">常见问题</a></li></ul>`,72)])])}const u=a(d,[["render",r]]);export{g as __pageData,u as default};
